                fun test() {
                    val pass = if (condition1) {
                        (
                            condition2
                        )
                    } else {
                        condition3
                    }
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
                .hasNoLintViolations()
        }

        @Test
        fun `Given intellij_idea code style, the closing paren is indented (default behavior)`() {
            val code =
                """
                fun test() {
                    val pass = if (condition1) {
                        (
                            condition2
                            )
                    } else {
                        condition3
                    }
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to intellij_idea)
                .hasNoLintViolations()
        }

        @Test
        fun `Given ktlint_official code style with multiline if condition, parenthesized expression should be consistent`() {
            val code =
                """
                fun test() {
                    if (
                        condition1
                    ) {
                        (
                            condition2
                        )
                    } else {
                        condition3
                    }
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
                .hasNoLintViolations()
        }

        @Test
        fun `Given ktlint_official code style with nested parenthesized expressions`() {
            val code =
                """
                fun test() {
                    val result = if (condition1) {
                        (
                            (
                                nestedCondition
                            )
                        )
                    } else {
                        other
                    }
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
                .hasNoLintViolations()
        }

        @Test
        fun `Given ktlint_official code style, parenthesized expression outside if should also have aligned closing paren`() {
            val code =
                """
                fun test() {
                    val result =
                        (
                            someExpression
                        )
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
                .hasNoLintViolations()
        }
    }
}
"}

